const code = $input.first().json.code || '';
const analysisType = $input.first().json.analysisType || 'full';

const findings = [];

// Reentrancy detection
const externalCallPattern = /\.call\{|\.transfer\(|\.send\(/g;
const stateChangePattern = /\w+\s*=|\w+\+\+|\w+--|\w+\s*\+=|\w+\s*-=/g;
const lines = code.split('\n');

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  // Check for reentrancy pattern
  if (externalCallPattern.test(line)) {
    // Look for state changes after external call
    for (let j = i + 1; j < Math.min(i + 10, lines.length); j++) {
      if (stateChangePattern.test(lines[j])) {
        findings.push({
          type: 'reentrancy',
          severity: 'Critical',
          line: i + 1,
          description: `Potential reentrancy: external call at line ${i+1} followed by state change at line ${j+1}`,
          code: line.trim()
        });
        break;
      }
    }
  }

  // Check for unchecked external calls
  if (/\.call\{/.test(line) && !/require\(|assert\(|if\s*\(/.test(line) && !/require\(|assert\(|if\s*\(/.test(lines[i-1] || '')) {
    findings.push({
      type: 'unchecked_call',
      severity: 'High',
      line: i + 1,
      description: 'External call without return value check',
      code: line.trim()
    });
  }

  // Check for integer overflow (pre-0.8.0)
  if (/pragma solidity \^0\.[0-7]\./.test(code) && /\+|\*|-/.test(line) && /uint|int/.test(lines[i-1] || '')) {
    findings.push({
      type: 'overflow_risk',
      severity: 'High',
      line: i + 1,
      description: 'Potential integer overflow in Solidity < 0.8.0 without SafeMath',
      code: line.trim()
    });
  }

  // Check for missing access control
  if (/function\s+\w+.*public/.test(line) && !/onlyOwner|onlyAdmin|require\(msg\.sender/.test(line)) {
    const funcName = line.match(/function\s+(\w+)/)?.[1];
    if (funcName && (funcName.includes('withdraw') || funcName.includes('transfer') || funcName.includes('set'))) {
      findings.push({
        type: 'access_control',
        severity: 'Medium',
        line: i + 1,
        description: `Public function '${funcName}' may need access control`,
        code: line.trim()
      });
    }
  }
}

return [{ json: { findings, totalIssues: findings.length, analysisComplete: true } }];

const params = $input.first().json;
const simulations = params.simulations || 10000;
const timeHorizon = params.timeHorizon || 365; // days

// Extract tokenomics parameters
const initialSupply = params.initialSupply || 1+1234567890;
const inflationRate = params.inflationRate || 0.05; // 5% annual
const distributionGini = params.distributionGini || 0.7; // Gini coefficient
const topHoldersPercent = params.topHoldersPercent || 0.3; // Top 10 holders own 30%

const results = {
  supplyProjections: [],
  inflationScenarios: [],
  centralizationRisks: [],
  stabilityMetrics: {}
};

// Monte Carlo simulation for token supply dynamics
for (let sim = 0; sim < simulations; sim++) {
  let supply = initialSupply;
  let dailyInflation = Math.pow(1 + inflationRate, 1/365) - 1;

  // Add randomness to inflation (±20% variance)
  const inflationVariance = 0.8 + Math.random() * 0.4;
  dailyInflation *= inflationVariance;

  for (let day = 0; day < timeHorizon; day++) {
    supply *= (1 + dailyInflation);
  }

  results.supplyProjections.push(supply);

  // Calculate inflation impact
  const totalInflation = (supply - initialSupply) / initialSupply;
  results.inflationScenarios.push(totalInflation);
}

// Governance centralization risk simulation
for (let sim = 0; sim < simulations; sim++) {
  // Simulate voting power concentration
  const whaleVotingPower = topHoldersPercent + (Math.random() - 0.5) * 0.1;
  const participationRate = 0.2 + Math.random() * 0.3; // 20-50% participation

  // Nakamoto coefficient (number of entities needed for 51% attack)
  const nakamotoCoeff = Math.floor(1 / whaleVotingPower) + Math.floor(Math.random() * 3);

  // Centralization risk score (0-1, higher = more centralized)
  const centralizationScore = whaleVotingPower * (1 - participationRate) * (10 / nakamotoCoeff);

  results.centralizationRisks.push({
    whaleVotingPower,
    participationRate,
    nakamotoCoeff,
    centralizationScore
  });
}

// Calculate statistical metrics
const mean = arr => arr.reduce((a, b) => a + b, 0) / arr.length;
const stdDev = arr => {
  const avg = mean(arr);
  return Math.sqrt(arr.reduce((sq, n) => sq + Math.pow(n - avg, 2), 0) / arr.length);
};
const percentile = (arr, p) => {
  const sorted = [...arr].sort((a, b) => a - b);
  return sorted[Math.floor(sorted.length * p)];
};

results.stabilityMetrics = {
  supplyMean: mean(results.supplyProjections),
  supplyStdDev: stdDev(results.supplyProjections),
  supply95thPercentile: percentile(results.supplyProjections, 0.95),
  inflationMean: mean(results.inflationScenarios),
  inflationStdDev: stdDev(results.inflationScenarios),
  avgCentralizationScore: mean(results.centralizationRisks.map(r => r.centralizationScore)),
  avgNakamotoCoeff: mean(results.centralizationRisks.map(r => r.nakamotoCoeff)),
  avgParticipationRate: mean(results.centralizationRisks.map(r => r.participationRate)),
  giniCoefficient: distributionGini,
  // DAO Stability Score (0-100, higher = more stable)
  daoStabilityScore: Math.max(0, Math.min(100, 
    100 - (mean(results.centralizationRisks.map(r => r.centralizationScore)) * 100) 
    - (stdDev(results.inflationScenarios) * 50)
    - ((1 - mean(results.centralizationRisks.map(r => r.participationRate))) * 30)
  ))
};

return [{ json: results }];

